const input = JSON.parse($input.item.json.chatInput || '{}');
const prices = input.prices || [];

if (!prices || prices.length === 0) {
  return { json: { error: 'No price data provided', metrics: null } };
}

const sorted = [...prices].sort((a, b) => new Date(b.date) - new Date(a.date));

function movingAverage(data, period) {
  if (data.length < period) return null;
  const slice = data.slice(0, period);
  const sum = slice.reduce((acc, p) => acc + parseFloat(p.close), 0);
  return Math.round((sum / period) * 100) / 100;
}

function pctChange(data, period) {
  if (data.length < period + 1) return null;
  const current = parseFloat(data[0].close);
  const past = parseFloat(data[period].close);
  return Math.round(((current - past) / past) * 10000) / 100;
}

function calculateVolatility(data) {
  if (data.length < 2) return null;
  const returns = [];
  for (let i = 0; i < Math.min(data.length - 1, 30); i++) {
    const today = parseFloat(data[i].close);
    const yesterday = parseFloat(data[i + 1].close);
    returns.push((today - yesterday) / yesterday);
  }
  const mean = returns.reduce((a, b) => a + b, 0) / returns.length;
  const variance = returns.reduce((a, r) => a + Math.pow(r - mean, 2), 0) / returns.length;
  return Math.round(Math.sqrt(variance) * 10000) / 100;
}

function volumeTrend(data) {
  if (data.length < 14) return 'insufficient_data';
  const recent7 = data.slice(0, 7).reduce((a, p) => a + parseFloat(p.volume || 0), 0) / 7;
  const prior7 = data.slice(7, 14).reduce((a, p) => a + parseFloat(p.volume || 0), 0) / 7;
  if (prior7 === 0) return 'unknown';
  const change = (recent7 - prior7) / prior7;
  if (change > 0.1) return 'increasing';
  if (change < -0.1) return 'decreasing';
  return 'stable';
}

const currentPrice = sorted.length > 0 ? parseFloat(sorted[0].close) : null;
const volatility = calculateVolatility(sorted);

return {
  json: {
    metrics: {
      current_price: currentPrice,
      moving_avg_7d: movingAverage(sorted, 7),
      moving_avg_30d: movingAverage(sorted, 30),
      pct_change_7d: pctChange(sorted, 7),
      pct_change_30d: pctChange(sorted, 30),
      volatility_pct: volatility,
      volatility_level: volatility > 3 ? 'High' : volatility > 1.5 ? 'Medium' : 'Low',
      volume_trend: volumeTrend(sorted),
      data_points_used: sorted.length
    }
  }
};

try {
  const input = JSON.parse($input.item.json.chatInput || '{}');

  const pctChange30d = parseFloat(input.pct_change_30d);
  const volatilityPct = parseFloat(input.volatility_pct);
  const volumeTrend = (input.volume_trend || 'stable').toLowerCase();
  const sentiment = (input.sentiment || 'neutral').toLowerCase();

  if (isNaN(pctChange30d)) {
    return { json: { error: 'Invalid input: pct_change_30d must be a number', score: null } };
  }
  if (isNaN(volatilityPct)) {
    return { json: { error: 'Invalid input: volatility_pct must be a number', score: null } };
  }

  // Momentum Score (30% weight)
  let momentumScore;
  if (pctChange30d >= 20) momentumScore = 100;
  else if (pctChange30d <= -20) momentumScore = 0;
  else momentumScore = Math.round(((pctChange30d + 20) / 40) * 100);

  // Volatility Score (25% weight) - lower is better
  let volatilityScore;
  if (volatilityPct <= 0) volatilityScore = 100;
  else if (volatilityPct >= 5) volatilityScore = 0;
  else volatilityScore = Math.round(((5 - volatilityPct) / 5) * 100);

  // Volume Score (20% weight)
  const pricePositive = pctChange30d > 0;
  let volumeScore;
  switch (volumeTrend) {
    case 'increasing': volumeScore = pricePositive ? 85 : 40; break;
    case 'stable': volumeScore = 60; break;
    case 'decreasing': volumeScore = pricePositive ? 50 : 30; break;
    default: volumeScore = 50;
  }

  // Sentiment Score (25% weight)
  let sentimentScore;
  switch (sentiment) {
    case 'positive': sentimentScore = 85; break;
    case 'neutral': sentimentScore = 55; break;
    case 'mixed': sentimentScore = 45; break;
    case 'negative': sentimentScore = 15; break;
    default: sentimentScore = 50;
  }

  // Composite Score
  const compositeScore = Math.round(
    momentumScore * 0.30 +
    volatilityScore * 0.25 +
    volumeScore * 0.20 +
    sentimentScore * 0.25
  );

  let rating;
  if (compositeScore >= 70) rating = 'Strong';
  else if (compositeScore >= 45) rating = 'Moderate';
  else rating = 'Weak';

  return {
    json: {
      health_score: {
        total: compositeScore,
        rating: rating,
        breakdown: {
          momentum: { score: momentumScore, weight: '30%', input: pctChange30d + '% 30d change' },
          volatility: { score: volatilityScore, weight: '25%', input: volatilityPct + '% daily volatility' },
          volume: { score: volumeScore, weight: '20%', input: volumeTrend + ' trend' },
          sentiment: { score: sentimentScore, weight: '25%', input: sentiment + ' sentiment' }
        },
        interpretation: compositeScore >= 70
          ? 'Stock shows strong fundamentals with positive momentum.'
          : compositeScore >= 45
          ? 'Stock shows moderate health with mixed signals. Monitor closely.'
          : 'Stock shows weakness across multiple factors. Exercise caution.'
      }
    }
  };
} catch (error) {
  return { json: { error: 'Health Scorer failed: ' + error.message, score: null } };
}
